package main

import (
	"encoding/gob"
	"fmt"
	"io/ioutil"
	"log"
	"os"
	"path/filepath"
	"sync"
	"time"
)

type Session struct {
	UserID       string
	Preferences  map[string]interface{}
	Permissions  []string
	LastAccessed time.Time
}

type SessionManager struct {
	sessions map[string]*Session
	mu       sync.RWMutex
	path     string
}

func NewSessionManager(path string) *SessionManager {
	sm := &SessionManager{
		sessions: make(map[string]*Session),
		path:     path,
	}
	sm.loadSessions()
	return sm
}

func (sm *SessionManager) CreateSession(userID string) string {
	sessionID := fmt.Sprintf("%d", time.Now().Unix())
	
	session := &Session{
		UserID:       userID,
		Preferences:  make(map[string]interface{}),
		Permissions:  make([]string, 0),
		LastAccessed: time.Now(),
	}
	
	sm.mu.Lock()
	sm.sessions[sessionID] = session
	sm.mu.Unlock()
	
	sm.saveSession(sessionID, session)
	return sessionID
}

func (sm *SessionManager) GetSession(sessionID string) (*Session, bool) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	
	session, exists := sm.sessions[sessionID]
	if !exists {
		return nil, false
	}
	
	session.LastAccessed = time.Now()
	sm.saveSession(sessionID, session)
	return session, true
}

func (sm *SessionManager) UpdateSession(sessionID string, updateFunc func(*Session)) bool {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	session, exists := sm.sessions[sessionID]
	if !exists {
		return false
	}
	
	updateFunc(session)
	session.LastAccessed = time.Now()
	sm.saveSession(sessionID, session)
	return true
}

func (sm *SessionManager) DeleteSession(sessionID string) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	delete(sm.sessions, sessionID)
	sm.deleteSessionFile(sessionID)
}

func (sm *SessionManager) saveSession(sessionID string, session *Session) {
	filePath := filepath.Join(sm.path, sessionID+".gob")
	
	file, err := os.Create(filePath)
	if err != nil {
		log.Printf("Error creating session file: %v", err)
		return
	}
	defer file.Close()
	
	encoder := gob.NewEncoder(file)
	err = encoder.Encode(session)
	if err != nil {
		log.Printf("Error encoding session: %v", err)
	}
}

func (sm *SessionManager) loadSessions() {
	files, err := ioutil.ReadDir(sm.path)
	if err != nil {
		log.Printf("Error reading session directory: %v", err)
		return
	}
	
	for _, file := range files {
		if filepath.Ext(file.Name()) == ".gob" {
			sessionID := strings.TrimSuffix(file.Name(), ".gob")
			sm.loadSession(sessionID)
		}
	}
}

func (sm *SessionManager) loadSession(sessionID string) {
	filePath := filepath.Join(sm.path, sessionID+".gob")
	
	file, err := os.Open(filePath)
	if err != nil {
		log.Printf("Error opening session file: %v", err)
		return
	}
	defer file.Close()
	
	var session Session
	decoder := gob.NewDecoder(file)
	err = decoder.Decode(&session)
	if err != nil {
		log.Printf("Error decoding session: %v", err)
		return
	}
	
	sm.mu.Lock()
	sm.sessions[sessionID] = &session
	sm.mu.Unlock()
}

func (sm *SessionManager) deleteSessionFile(sessionID string) {
	filePath := filepath.Join(sm.path, sessionID+".gob")
	os.Remove(filePath)
}

func (sm *SessionManager) CleanupExpiredSessions(expiration time.Duration) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	
	now := time.Now()
	for sessionID, session := range sm.sessions {
		if now.Sub(session.LastAccessed) > expiration {
			delete(sm.sessions, sessionID)
			sm.deleteSessionFile(sessionID)
		}
	}
}

